<?php
declare(strict_types=1); namespace Vigilancia\Database; use PDO;use RuntimeException;
final class MigrationRunner{public function __construct(private PDO $pdo,private string $path){}public function run():array{$this->pdo->exec("CREATE TABLE IF NOT EXISTS migrations (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, version VARCHAR(100) NOT NULL UNIQUE, batch INT UNSIGNED NOT NULL, executed_at DATETIME NOT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");$batch=(int)$this->pdo->query("SELECT COALESCE(MAX(batch),0)+1 FROM migrations")->fetchColumn();$done=$this->pdo->query("SELECT version FROM migrations")->fetchAll(PDO::FETCH_COLUMN);$applied=[];foreach(glob($this->path.'/*.php')?:[] as $file){$version=basename($file,'.php');if(in_array($version,$done,true))continue;$migration=require $file;if(!is_callable($migration))throw new RuntimeException("Migración inválida: {$version}");$migration($this->pdo);$stmt=$this->pdo->prepare("INSERT INTO migrations(version,batch,executed_at) VALUES(?,?,UTC_TIMESTAMP())");$stmt->execute([$version,$batch]);$applied[]=$version;}return $applied;}}
